// src/main.js

// 1. 引入配置模块
import Config from '@/core/config.js';
import Log from "@/util/log.js";
import log from "@/util/log.js";

// 2. 创建一个全局对象 Pz，把 Config 放进去
const Pz = {
    Config,
    Log
};

// 3. 【核心魔法】
// 如果是浏览器环境，把它挂载到 window 上
// 这样 HTML 里的 <script> 就能通过 window.Pz (即 Pz) 访问到它
if (typeof window !== 'undefined') {
    window.Pz = Pz;
    console.log("破竹UI -- 已加载到全局 (window.Pz)")
}

// 4. 默认导出 Pz
// 这样 Vue 项目里 import Pz from '...' 时，拿到的也是这个 Pz 对象
export default Pz;