/*
 配置文件
 */

const _data = {
    debug : false,
    log : "info",
}

const ALLOWED_KEYS = ['log'];

// 定义库文件的特征标识，用于在堆栈中过滤掉它们
const LIB_FILE_PATTERNS = ['config.js', 'pz-ui.js', 'node_modules', 'webpack:', 'vite:'];

function getCallerLocation() {
    const stack = new Error().stack;
    if (!stack) return "未知位置";

    const lines = stack.split('\n');

    for (let i = 2; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        // 匹配文件路径和行号
        const match = line.match(/\((.+):(\d+):(\d+)\)$/) || line.match(/at (.+):(\d+):(\d+)$/);

        if (match) {
            const fullPath = match[1] || match[4];
            const fileName = fullPath.split('/').pop().split('\\').pop();
            const lineNum = match[2] || match[5];

            // 跳过库文件
            const isLibFile = LIB_FILE_PATTERNS.some(pattern => fullPath.includes(pattern));
            if (isLibFile) {
                continue;
            }

            const cleanName = fileName.split('?')[0];
            return `${cleanName}:${lineNum}`;
        }
    }

    return "内联脚本 (请全局搜索 Config.Debug)";
}

const Config = {
    Get (key){
        return _data[key];
    },

    Debug(){
        _data.debug = true;

        const location = getCallerLocation();

        // 1. 定义统一的样式：黄底 + 红字 + 加粗
        const unifiedStyle = [
            'background: #fffbe6',       // 浅黄色背景
            'color: #d32f2f',            // 统一深红色文字
            'padding: 6px 10px',         // 内边距
            'border-radius: 4px',        // 圆角
            'font-weight: bold',         // 加粗
            'font-family: Consolas, Monaco, monospace', // 等宽字体，方便看文件名和行号
            'border: 1px solid #ffc107', // 金色边框
            'font-size: 13px',
            'display: inline-block',
        ].join(';');

        // 2. 构建单一字符串
        const message = `⚠️ 调试模式已开启！上线前请移除，位置：${location}`;

        console.log(`%c ${message}`, unifiedStyle);
    },

    Setkey(key, value){
        if(!ALLOWED_KEYS.includes(key)){
            console.log(`禁止修改配置：${key}`)
            return;
        }
        _data[key] = value;
        console.log(`已修改配置：${key} = ${value}`)
    }
};

export default Config;